code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int D = sc.nextInt();
            int [][][] dp = new int[N][D][D];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < D; j++) {
                    for (int k = 0; k < D; k++) {
                        dp[i][j][k] = Integer.MAX_VALUE;
                    }
                }
            }
            dp[0][0][0] = 0;
            for (int i = 0; i < D; i++) {
                for (int j = 0; j < D; j++) {
                    for (int k = 0; k < D; k++) {
                        if (i + j + k > 0) {
                            int val = (i ^ j ^ k) * (i + j + k);
                            if (i > 0) dp[0][j][k] = Math.min(dp[0][j][k], dp[0][j][k] + val);
                            if (j > 0) dp[0][j][k] = Math.min(dp[0][j][k], dp[0][j-1][k] + val);
                            if (k > 0) dp[0][j][k] = Math.min(dp[0][j][k], dp[0][j][k-1] + val);
                        }
                    }
                }
            }
            System.out.println(dp[0][D-1][D-1]);
        }
    }
}

